import{_ as a,o as r,c as l,ag as d}from"./chunks/framework.C6K0jwmI.js";const u=JSON.parse('{"title":"Part 4 — 売上とレポート","description":"","frontmatter":{"title":"Part 4 — 売上とレポート","audience":"オーナー / 店長","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"operations/part4-reports.md","filePath":"operations/part4-reports.md"}'),e={name:"operations/part4-reports.md"};function o(i,t,h,n,s,c){return r(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="part-4-—-売上とレポート" tabindex="-1">Part 4 — 売上とレポート <a class="header-anchor" href="#part-4-—-売上とレポート" aria-label="Permalink to &quot;Part 4 — 売上とレポート&quot;">​</a></h1><p>このページでは、お店の売上・品目別ランキング・スタッフ評価・顧客分析などの各種レポートの見方と活用方法を説明します。</p><div class="tip custom-block"><p class="custom-block-title">レポートの種類と見る画面</p><p>レポートは以下の 2 つの画面に分かれています。</p><ul><li><strong>管理画面の「レポート」タブ</strong>（マネージャー以上）: 基本レポート全般</li><li><strong>オーナー管理画面のタブ</strong>（オーナー専用）: ABC 分析、クロス店舗レポート</li></ul></div><hr><h2 id="_4-1-日次売上の見方" tabindex="-1">4-1. 日次売上の見方 <a class="header-anchor" href="#_4-1-日次売上の見方" aria-label="Permalink to &quot;4-1. 日次売上の見方&quot;">​</a></h2><h3 id="_4-1-1-売上レポートを開く" tabindex="-1">4-1-1. 売上レポートを開く <a class="header-anchor" href="#_4-1-1-売上レポートを開く" aria-label="Permalink to &quot;4-1-1. 売上レポートを開く&quot;">​</a></h3><ol><li>管理画面にマネージャー以上でログイン</li><li>上部タブ <strong>【レポート】</strong> → サブタブ <strong>【売上レポート】</strong></li><li>画面が開く</li></ol><h3 id="_4-1-2-表示される項目" tabindex="-1">4-1-2. 表示される項目 <a class="header-anchor" href="#_4-1-2-表示される項目" aria-label="Permalink to &quot;4-1-2. 表示される項目&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>売上合計</td><td>期間内の税込売上合計</td></tr><tr><td>注文件数</td><td>注文数</td></tr><tr><td>客単価</td><td>売上合計 ÷ 注文件数</td></tr><tr><td>時間帯別売上</td><td>1時間ごとの売上推移（棒グラフ）</td></tr><tr><td>日別売上推移</td><td>過去 7 / 30 / 90 日の折れ線グラフ</td></tr><tr><td>支払方法別</td><td>現金・カード・QR の内訳（円グラフ）</td></tr></tbody></table><h3 id="_4-1-3-期間選択" tabindex="-1">4-1-3. 期間選択 <a class="header-anchor" href="#_4-1-3-期間選択" aria-label="Permalink to &quot;4-1-3. 期間選択&quot;">​</a></h3><p>画面上部に期間切替ボタン:</p><ul><li><strong>日次</strong>: 本日の売上</li><li><strong>週次</strong>: 今週月〜日</li><li><strong>月次</strong>: 今月</li><li><strong>カスタム</strong>: 任意の開始日〜終了日</li></ul><h3 id="_4-1-4-活用例" tabindex="-1">4-1-4. 活用例 <a class="header-anchor" href="#_4-1-4-活用例" aria-label="Permalink to &quot;4-1-4. 活用例&quot;">​</a></h3><ul><li>毎朝「昨日の売上」確認</li><li>週次ミーティングで「先週の合計」報告</li><li>月次決算で「月間売上」集計</li><li>同じ曜日の比較（例: 先週金曜と今週金曜）</li></ul><hr><h2 id="_4-2-商品別ランキング" tabindex="-1">4-2. 商品別ランキング <a class="header-anchor" href="#_4-2-商品別ランキング" aria-label="Permalink to &quot;4-2. 商品別ランキング&quot;">​</a></h2><h3 id="_4-2-1-見方" tabindex="-1">4-2-1. 見方 <a class="header-anchor" href="#_4-2-1-見方" aria-label="Permalink to &quot;4-2-1. 見方&quot;">​</a></h3><ol><li>【売上レポート】 内の <strong>「商品別ランキング」</strong> セクション（同じタブ内の下スクロール）</li><li>売上順に品目が表示</li><li>各品目の情報:</li></ol><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>商品名</td><td>メニュー名</td></tr><tr><td>販売数</td><td>期間内の注文数</td></tr><tr><td>売上合計</td><td>円単位</td></tr><tr><td>粗利</td><td>売上 − 原価（レシピ設定時のみ表示）</td></tr></tbody></table><h3 id="_4-2-2-活用例" tabindex="-1">4-2-2. 活用例 <a class="header-anchor" href="#_4-2-2-活用例" aria-label="Permalink to &quot;4-2-2. 活用例&quot;">​</a></h3><ul><li><strong>上位 10 品</strong>: 看板メニューの把握、在庫発注優先度</li><li><strong>下位 10 品</strong>: 廃止候補・値引き候補</li><li><strong>粗利率ランキング</strong>: 利益率の高い品目を積極プッシュ</li></ul><hr><h2 id="_4-3-abc-分析-オーナー専用" tabindex="-1">4-3. ABC 分析（オーナー専用） <a class="header-anchor" href="#_4-3-abc-分析-オーナー専用" aria-label="Permalink to &quot;4-3. ABC 分析（オーナー専用）&quot;">​</a></h2><p>ABC 分析は <strong>オーナー管理画面の専用タブ</strong> で確認します。マネージャー・スタッフには表示されません。</p><h3 id="_4-3-1-開く手順" tabindex="-1">4-3-1. 開く手順 <a class="header-anchor" href="#_4-3-1-開く手順" aria-label="Permalink to &quot;4-3-1. 開く手順&quot;">​</a></h3><ol><li>オーナーアカウントでオーナー管理画面を開く</li><li>上部タブ <strong>【ABC 分析】</strong></li></ol><h3 id="_4-3-2-a-b-c-の定義" tabindex="-1">4-3-2. A / B / C の定義 <a class="header-anchor" href="#_4-3-2-a-b-c-の定義" aria-label="Permalink to &quot;4-3-2. A / B / C の定義&quot;">​</a></h3><p>売上累積シェアで 3 ランクに分類:</p><table tabindex="0"><thead><tr><th>ランク</th><th>シェア</th><th>意味</th><th>対応方針</th></tr></thead><tbody><tr><td><strong>A ランク</strong></td><td>売上上位 70%</td><td>主力商品</td><td><strong>品切れ厳禁</strong>、メイン訴求に使う</td></tr><tr><td><strong>B ランク</strong></td><td>70〜90%</td><td>安定商品</td><td>現状維持、プラスアルファの訴求</td></tr><tr><td><strong>C ランク</strong></td><td>90〜100%</td><td>下位商品</td><td><strong>廃止候補</strong> / メニュー見直し / 値下げ検討</td></tr></tbody></table><h3 id="_4-3-3-活用例" tabindex="-1">4-3-3. 活用例 <a class="header-anchor" href="#_4-3-3-活用例" aria-label="Permalink to &quot;4-3-3. 活用例&quot;">​</a></h3><ul><li>全 50 品のうち C ランク 25 品を見直し</li><li>A ランクの原材料を優先発注</li><li>A ランクの新規バリエーション開発（例: 「醤油ラーメン」が A → 「辛味噌ラーメン」を追加）</li></ul><hr><h2 id="_4-4-バスケット分析-併売分析" tabindex="-1">4-4. バスケット分析（併売分析） <a class="header-anchor" href="#_4-4-バスケット分析-併売分析" aria-label="Permalink to &quot;4-4. バスケット分析（併売分析）&quot;">​</a></h2><p>「○○を注文した人は △△ も買う」傾向を分析。</p><h3 id="_4-4-1-見方" tabindex="-1">4-4-1. 見方 <a class="header-anchor" href="#_4-4-1-見方" aria-label="Permalink to &quot;4-4-1. 見方&quot;">​</a></h3><ol><li>管理画面 → 【レポート】 → サブタブ <strong>【併売分析】</strong></li><li>品目の組み合わせがリフト値順に表示</li></ol><h3 id="_4-4-2-リフト値とは" tabindex="-1">4-4-2. リフト値とは <a class="header-anchor" href="#_4-4-2-リフト値とは" aria-label="Permalink to &quot;4-4-2. リフト値とは&quot;">​</a></h3><p>「Aを買った人がBも買う確率 ÷ 全注文でBが買われる確率」</p><ul><li>リフト値 &gt; 1: 一緒に買われやすい</li><li>リフト値 = 1: 関係なし（独立）</li><li>リフト値 &lt; 1: むしろ一緒には買われにくい</li></ul><p>例: <strong>ラーメン + 餃子</strong> のリフト値 = 2.5 → ラーメンを食べる人は通常の 2.5 倍の確率で餃子も頼む</p><h3 id="_4-4-3-活用例" tabindex="-1">4-4-3. 活用例 <a class="header-anchor" href="#_4-4-3-活用例" aria-label="Permalink to &quot;4-4-3. 活用例&quot;">​</a></h3><ul><li><strong>セットメニュー提案</strong>: 「ラーメン + 餃子」セットを作って単価アップ</li><li><strong>レコメンド</strong>: セルフメニューで「一緒にいかがですか？」で餃子を推薦</li><li><strong>メニュー配置</strong>: 一緒に頼まれる品目を隣接ページに配置</li></ul><hr><h2 id="_4-5-回転率・客層レポート" tabindex="-1">4-5. 回転率・客層レポート <a class="header-anchor" href="#_4-5-回転率・客層レポート" aria-label="Permalink to &quot;4-5. 回転率・客層レポート&quot;">​</a></h2><h3 id="_4-5-1-開く手順" tabindex="-1">4-5-1. 開く手順 <a class="header-anchor" href="#_4-5-1-開く手順" aria-label="Permalink to &quot;4-5-1. 開く手順&quot;">​</a></h3><ol><li>管理画面 → 【レポート】 → サブタブ <strong>【回転率・客層】</strong></li></ol><h3 id="_4-5-2-表示される指標" tabindex="-1">4-5-2. 表示される指標 <a class="header-anchor" href="#_4-5-2-表示される指標" aria-label="Permalink to &quot;4-5-2. 表示される指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th><th>活用</th></tr></thead><tbody><tr><td>平均滞在時間</td><td>着席から会計までの時間（分）</td><td>15 分以下なら回転率高い、90 分以上ならゆっくり利用</td></tr><tr><td>1 日の回転数</td><td>1 テーブルあたり何回お客様が入れ替わったか</td><td>高いほど効率的、低いなら滞在時間長い客が多い</td></tr><tr><td>時間帯別回転傾向</td><td>時間帯ごとの客数推移</td><td>ピーク時間の把握、ラストオーダーの最適化</td></tr><tr><td>曜日別傾向</td><td>月〜日の平均客数</td><td>シフト配置の最適化</td></tr></tbody></table><hr><h2 id="_4-6-スタッフ評価レポート" tabindex="-1">4-6. スタッフ評価レポート <a class="header-anchor" href="#_4-6-スタッフ評価レポート" aria-label="Permalink to &quot;4-6. スタッフ評価レポート&quot;">​</a></h2><h3 id="_4-6-1-開く手順" tabindex="-1">4-6-1. 開く手順 <a class="header-anchor" href="#_4-6-1-開く手順" aria-label="Permalink to &quot;4-6-1. 開く手順&quot;">​</a></h3><ol><li>管理画面 → 【レポート】 → サブタブ <strong>【スタッフ評価】</strong></li></ol><h3 id="_4-6-2-スタッフごとに表示" tabindex="-1">4-6-2. スタッフごとに表示 <a class="header-anchor" href="#_4-6-2-スタッフごとに表示" aria-label="Permalink to &quot;4-6-2. スタッフごとに表示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>スタッフ名</td><td>登録されている表示名</td></tr><tr><td>注文入力件数</td><td>ハンディで取った注文数</td></tr><tr><td>売上貢献</td><td>担当した注文の金額合計</td></tr><tr><td>客単価</td><td>担当注文の客単価</td></tr><tr><td>満足度評価</td><td>お客様からの星評価平均（5 段階）</td></tr><tr><td>勤務日数</td><td>期間内の出勤日数</td></tr></tbody></table><h3 id="_4-6-3-活用例" tabindex="-1">4-6-3. 活用例 <a class="header-anchor" href="#_4-6-3-活用例" aria-label="Permalink to &quot;4-6-3. 活用例&quot;">​</a></h3><ul><li><strong>月次評価・ボーナス査定</strong>: 数値ベースで公平に評価</li><li><strong>研修対象の発見</strong>: 客単価が低いスタッフは接客改善研修</li><li><strong>優秀スタッフの昇格判断</strong>: 全指標が高いスタッフはマネージャー候補</li></ul><hr><h2 id="_4-7-満足度・低評価分析" tabindex="-1">4-7. 満足度・低評価分析 <a class="header-anchor" href="#_4-7-満足度・低評価分析" aria-label="Permalink to &quot;4-7. 満足度・低評価分析&quot;">​</a></h2><p>お客様のセルフ注文画面で送信された星評価（1〜5）を集計し、店舗運営の改善に活用するレポートです。低評価（1〜2）には、お客様が任意で選んだ理由コードと自由コメントが含まれる場合があります。</p><div class="warning custom-block"><p class="custom-block-title">スタッフ個人評価ではなく、改善材料として扱ってください</p><ul><li>顧客のセルフ注文経由の評価では、担当スタッフが特定されないケースが多くあります。</li><li>同じ品目に低評価が集中している場合、原因はレシピ・温度・盛り付け・提供時間など店舗オペレーション側にあることが多いです。</li><li>「低評価が多い時間帯 = ピーク時の人員不足や提供導線の混雑」のように、運営改善のヒントとして使ってください。</li><li>個別のスタッフを責める材料には使わないでください。</li></ul></div><h3 id="_4-7-1-開く手順" tabindex="-1">4-7-1. 開く手順 <a class="header-anchor" href="#_4-7-1-開く手順" aria-label="Permalink to &quot;4-7-1. 開く手順&quot;">​</a></h3><ol><li>管理画面 → 上部タブ <strong>【レポート】</strong> → サブタブ <strong>【満足度分析】</strong></li><li>期間を選び、【表示】ボタンを押す（今日 / 昨日 / 今週 / 今月のプリセットあり）</li></ol><h3 id="_4-7-2-サマリーカード" tabindex="-1">4-7-2. サマリーカード <a class="header-anchor" href="#_4-7-2-サマリーカード" aria-label="Permalink to &quot;4-7-2. サマリーカード&quot;">​</a></h3><p>画面上部に以下が並びます。</p><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>評価件数</td><td>期間内に届いた星評価の総数</td></tr><tr><td>平均評価</td><td>1〜5 の平均値</td></tr><tr><td>低評価件数</td><td>星 1〜2 の件数</td></tr><tr><td>低評価率</td><td>低評価件数 ÷ 評価件数</td></tr><tr><td>高評価件数</td><td>星 4〜5 の件数</td></tr></tbody></table><h3 id="_4-7-3-低評価の理由ランキング" tabindex="-1">4-7-3. 低評価の理由ランキング <a class="header-anchor" href="#_4-7-3-低評価の理由ランキング" aria-label="Permalink to &quot;4-7-3. 低評価の理由ランキング&quot;">​</a></h3><p>低評価を選んだお客様が任意で送ってくれた理由を集計します。</p><table tabindex="0"><thead><tr><th>理由コード</th><th>表示ラベル</th></tr></thead><tbody><tr><td><code>slow_service</code></td><td>提供が遅かった</td></tr><tr><td><code>taste</code></td><td>味が好みではなかった</td></tr><tr><td><code>temperature</code></td><td>温度が気になった</td></tr><tr><td><code>portion</code></td><td>量が気になった</td></tr><tr><td><code>wrong_item</code></td><td>注文内容と違った</td></tr><tr><td><code>staff</code></td><td>接客が気になった</td></tr><tr><td><code>cleanliness</code></td><td>清潔感が気になった</td></tr><tr><td><code>price</code></td><td>価格が気になった</td></tr><tr><td><code>other</code></td><td>その他</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">理由送信は任意です</p><p>お客様には負担をかけないよう、理由選択は任意設定です。理由なしで星だけ送られてきたケースもこのテーブルには現れません。理由が集まらないからといって低評価を軽視せず、品目ランキング・時間帯ランキングと併せて確認してください。</p></div><h3 id="_4-7-4-低評価が出た品目ランキング" tabindex="-1">4-7-4. 低評価が出た品目ランキング <a class="header-anchor" href="#_4-7-4-低評価が出た品目ランキング" aria-label="Permalink to &quot;4-7-4. 低評価が出た品目ランキング&quot;">​</a></h3><p>品目ごとの低評価件数・平均評価・最終発生時刻を一覧表示します。</p><p><strong>活用例:</strong></p><ul><li>同じ品目が常に上位 → レシピ・温度・盛り付けを確認</li><li>一時的に上位 → 食材ロット・調理担当の交代タイミング・ピーク時のオペレーションを確認</li><li>平均評価が 2 を切っている品目 → 一時的な販売停止や改善試作を検討</li></ul><h3 id="_4-7-5-時間帯別-低評価" tabindex="-1">4-7-5. 時間帯別 低評価 <a class="header-anchor" href="#_4-7-5-時間帯別-低評価" aria-label="Permalink to &quot;4-7-5. 時間帯別 低評価&quot;">​</a></h3><p>0〜23 時の各時間帯について、評価件数・低評価数・低評価率を表示します（評価が無い時間帯は 0 件で並びます）。</p><p><strong>活用例:</strong></p><ul><li>ランチピーク（12 時台）に低評価率が突出 → 人員配置・調理キャパシティ・提供順序を見直し</li><li>夜営業のラストオーダー前（22 時台等）の低評価が多い → 在庫切れによる代替対応・温度管理を確認</li><li>開店直後の低評価が多い → 仕込み完了タイミング・予熱不足を確認</li></ul><h3 id="_4-7-6-直近の低評価一覧" tabindex="-1">4-7-6. 直近の低評価一覧 <a class="header-anchor" href="#_4-7-6-直近の低評価一覧" aria-label="Permalink to &quot;4-7-6. 直近の低評価一覧&quot;">​</a></h3><p>最大 50 件の低評価を新しい順に表示します。</p><table tabindex="0"><thead><tr><th>列</th><th>説明</th></tr></thead><tbody><tr><td>日時</td><td>評価が送信された日時</td></tr><tr><td>品目</td><td>該当の料理</td></tr><tr><td>評価</td><td>星の数 (1〜2)</td></tr><tr><td>理由</td><td>お客様が選んだ理由ラベル（任意）</td></tr><tr><td>コメント</td><td>お客様の自由記述（任意・最大 255 文字）</td></tr><tr><td>注文</td><td>注文 ID の短縮表示</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">コメントの扱い</p><p>自由コメントは、お客様が「気になったこと」を率直に書いてくれている場合があります。否定的な書き方でも責めの意図ではないことが多いので、改善材料として冷静に読んでください。スタッフ個人を名指しするコメントが入った場合は、内容を確認したうえで該当スタッフと一対一で話し合うなど、適切な配慮をしてください。</p></div><h3 id="_4-7-7-全店舗合算で見る-オーナーのみ" tabindex="-1">4-7-7. 全店舗合算で見る (オーナーのみ) <a class="header-anchor" href="#_4-7-7-全店舗合算で見る-オーナーのみ" aria-label="Permalink to &quot;4-7-7. 全店舗合算で見る (オーナーのみ)&quot;">​</a></h3><p>オーナーアカウントでオーナー管理画面 →【全店舗横断レポート】を開くと、末尾に <strong>満足度サマリー</strong> が表示されます。</p><ul><li>全店舗合算の平均評価・低評価率</li><li>店舗別 平均評価・低評価率</li><li>低評価が多い品目ランキング（全店舗合算）</li><li>低評価の理由ランキング（全店舗合算）</li></ul><p>複数店舗を比較して、店舗別の改善優先度を判断するのに役立ちます。</p><div class="warning custom-block"><p class="custom-block-title">店舗別と全店合算で件数がわずかにずれることがあります</p><p>店舗別の満足度分析は <strong>営業日区切り</strong> で集計、全店舗横断の満足度サマリーは <strong>暦日 + 余白付き</strong> の簡易範囲で集計しています。これは横断レポート全体（売上品目・キャンセル品目・迷い品目）と同じ集計レンジを使うためで、深夜営業の店舗で数件の差が出る可能性があります。</p></div><hr><h2 id="_4-8-予約レポート" tabindex="-1">4-8. 予約レポート <a class="header-anchor" href="#_4-8-予約レポート" aria-label="Permalink to &quot;4-8. 予約レポート&quot;">​</a></h2><h3 id="_4-8-1-開く手順" tabindex="-1">4-8-1. 開く手順 <a class="header-anchor" href="#_4-8-1-開く手順" aria-label="Permalink to &quot;4-8-1. 開く手順&quot;">​</a></h3><ol><li>管理画面 → 上部タブ <strong>【予約管理】</strong> → サブタブの予約台帳内に統計セクション</li><li>期間を選び、予約数・来店人数・キャンセル率などを確認する</li></ol><h3 id="_4-8-2-指標" tabindex="-1">4-8-2. 指標 <a class="header-anchor" href="#_4-8-2-指標" aria-label="Permalink to &quot;4-8-2. 指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>予約総数</td><td>期間内の予約数</td></tr><tr><td>来店人数</td><td>実際に来店した予約の人数合計</td></tr><tr><td>無断キャンセル率</td><td>来店しなかった予約の割合</td></tr><tr><td>キャンセル率</td><td>キャンセルされた予約の割合</td></tr><tr><td>予約経路別</td><td>Web予約 / 電話予約 / 予約なし来店 / AI予約 の内訳</td></tr><tr><td>日別・時間帯別・曜日別</td><td>需要予測に活用</td></tr></tbody></table><hr><h2 id="_4-9-クロス店舗レポート-オーナー向け" tabindex="-1">4-9. クロス店舗レポート（オーナー向け） <a class="header-anchor" href="#_4-9-クロス店舗レポート-オーナー向け" aria-label="Permalink to &quot;4-9. クロス店舗レポート（オーナー向け）&quot;">​</a></h2><p>複数店舗の売上・客数・業績を横並びで比較。満足度サマリー（§4-7-7）も同じレポート末尾に表示されます。</p><h3 id="_4-9-1-開く手順" tabindex="-1">4-9-1. 開く手順 <a class="header-anchor" href="#_4-9-1-開く手順" aria-label="Permalink to &quot;4-9-1. 開く手順&quot;">​</a></h3><ol><li>オーナーアカウントでオーナー管理画面を開く</li><li>上部タブ <strong>【クロス店舗レポート】</strong></li></ol><h3 id="_4-9-2-表示項目" tabindex="-1">4-9-2. 表示項目 <a class="header-anchor" href="#_4-9-2-表示項目" aria-label="Permalink to &quot;4-9-2. 表示項目&quot;">​</a></h3><ul><li>店舗ごとの売上合計</li><li>店舗ごとの客数</li><li>店舗ごとの客単価</li><li>全店平均・最大・最小のベンチマーク</li><li>期間別（日次・週次・月次）</li><li>満足度サマリー（全店舗合算 + 店舗別 + 低評価品目 / 理由ランキング）</li></ul><h3 id="_4-9-3-活用例" tabindex="-1">4-9-3. 活用例 <a class="header-anchor" href="#_4-9-3-活用例" aria-label="Permalink to &quot;4-9-3. 活用例&quot;">​</a></h3><ul><li>全 3 店舗のうち 1 店舗だけ売上低い → 原因調査（立地 / スタッフ / メニュー）</li><li>業績トップ店舗の成功要因を他店舗に横展開</li><li>低評価が一店舗に集中 → §4-7 と併せて品目・時間帯・運営の改善ポイント特定</li></ul><hr><h2 id="_4-10-レジ分析-レジ締め精算レポート" tabindex="-1">4-10. レジ分析（レジ締め精算レポート） <a class="header-anchor" href="#_4-10-レジ分析-レジ締め精算レポート" aria-label="Permalink to &quot;4-10. レジ分析（レジ締め精算レポート）&quot;">​</a></h2><h3 id="_4-10-1-開く手順" tabindex="-1">4-10-1. 開く手順 <a class="header-anchor" href="#_4-10-1-開く手順" aria-label="Permalink to &quot;4-10-1. 開く手順&quot;">​</a></h3><ol><li>管理画面 → 【レポート】 → サブタブ <strong>【レジ分析】</strong></li></ol><h3 id="_4-10-2-表示項目" tabindex="-1">4-10-2. 表示項目 <a class="header-anchor" href="#_4-10-2-表示項目" aria-label="Permalink to &quot;4-10-2. 表示項目&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>レジ開閉履歴</td><td>いつ・誰が開けた / 閉めたか</td></tr><tr><td>日別キャッシュログ</td><td>入金・出金・過不足の履歴</td></tr><tr><td>予想在高 vs 実際</td><td>差額がプラスなら過多、マイナスなら不足</td></tr><tr><td>過不足アラート</td><td>閾値（デフォルト ¥500）を超える差額は警告</td></tr></tbody></table><h3 id="_4-10-3-活用例" tabindex="-1">4-10-3. 活用例 <a class="header-anchor" href="#_4-10-3-活用例" aria-label="Permalink to &quot;4-10-3. 活用例&quot;">​</a></h3><ul><li>毎日のレジ締めで過不足チェック</li><li>過不足が続くスタッフの現金取扱い研修</li><li>入金・出金記録漏れのチェック</li></ul><hr><h2 id="_4-11-注文履歴" tabindex="-1">4-11. 注文履歴 <a class="header-anchor" href="#_4-11-注文履歴" aria-label="Permalink to &quot;4-11. 注文履歴&quot;">​</a></h2><h3 id="_4-11-1-開く手順" tabindex="-1">4-11-1. 開く手順 <a class="header-anchor" href="#_4-11-1-開く手順" aria-label="Permalink to &quot;4-11-1. 開く手順&quot;">​</a></h3><ol><li>管理画面 → 【レポート】 → サブタブ <strong>【注文履歴】</strong></li></ol><h3 id="_4-11-2-表示項目" tabindex="-1">4-11-2. 表示項目 <a class="header-anchor" href="#_4-11-2-表示項目" aria-label="Permalink to &quot;4-11-2. 表示項目&quot;">​</a></h3><ul><li>全注文の一覧（日時・テーブル・品目・金額・ステータス）</li><li>検索フィルタ（日時・テーブル・品目・ステータス）</li><li>CSV エクスポート可</li></ul><h3 id="_4-11-3-活用例" tabindex="-1">4-11-3. 活用例 <a class="header-anchor" href="#_4-11-3-活用例" aria-label="Permalink to &quot;4-11-3. 活用例&quot;">​</a></h3><ul><li>「先週金曜の 19 時の注文を確認したい」等の個別調査</li><li>クレーム対応: お客様から「○○を頼んだはず」と言われた時の確認</li><li>税務監査対応: 過去の取引記録</li></ul><hr><h2 id="_4-12-csv-エクスポートの方法" tabindex="-1">4-12. CSV エクスポートの方法 <a class="header-anchor" href="#_4-12-csv-エクスポートの方法" aria-label="Permalink to &quot;4-12. CSV エクスポートの方法&quot;">​</a></h2><p>各レポートの <strong>【CSV 出力】</strong> ボタンから:</p><ol><li>期間を選択</li><li><strong>【CSV ダウンロード】</strong></li><li>ダウンロードフォルダに保存</li><li>Excel / Numbers / Google Sheets で開く</li></ol><h3 id="文字化け対処" tabindex="-1">文字化け対処 <a class="header-anchor" href="#文字化け対処" aria-label="Permalink to &quot;文字化け対処&quot;">​</a></h3><ul><li>Excel の場合: 「データ」→「テキストから」でインポート時に UTF-8 指定</li><li>Numbers / Google Sheets: デフォルト UTF-8 で OK</li></ul><hr><h2 id="_4-13-活用ストーリー例" tabindex="-1">4-13. 活用ストーリー例 <a class="header-anchor" href="#_4-13-活用ストーリー例" aria-label="Permalink to &quot;4-13. 活用ストーリー例&quot;">​</a></h2><h3 id="例-1-月次決算-毎月-1-日の作業" tabindex="-1">例 1: 月次決算（毎月 1 日の作業） <a class="header-anchor" href="#例-1-月次決算-毎月-1-日の作業" aria-label="Permalink to &quot;例 1: 月次決算（毎月 1 日の作業）&quot;">​</a></h3><ol><li>先月の <strong>売上レポート（月次）</strong> で合計売上を確認</li><li><strong>ABC 分析</strong> で主力商品の推移を見る</li><li><strong>スタッフ評価</strong> で最優秀スタッフにボーナス</li><li><strong>レジ分析</strong> で過不足合計を確認</li></ol><h3 id="例-2-新メニュー導入判断-週次" tabindex="-1">例 2: 新メニュー導入判断（週次） <a class="header-anchor" href="#例-2-新メニュー導入判断-週次" aria-label="Permalink to &quot;例 2: 新メニュー導入判断（週次）&quot;">​</a></h3><ol><li><strong>バスケット分析</strong> で既存メニューの組み合わせ傾向を把握</li><li><strong>ABC 分析</strong> で C ランク品目を特定</li><li>C ランク廃止 → 新メニュー追加の判断</li></ol><h3 id="例-3-スタッフ配置の最適化-月-1-回" tabindex="-1">例 3: スタッフ配置の最適化（月 1 回） <a class="header-anchor" href="#例-3-スタッフ配置の最適化-月-1-回" aria-label="Permalink to &quot;例 3: スタッフ配置の最適化（月 1 回）&quot;">​</a></h3><ol><li><strong>回転率レポート</strong> の時間帯別で、ピーク時間を特定</li><li><strong>スタッフ評価</strong> で客単価の高いスタッフを把握</li><li>ピーク時間に優秀スタッフを配置</li></ol><hr><h2 id="_4-14-よくある質問" tabindex="-1">4-14. よくある質問 <a class="header-anchor" href="#_4-14-よくある質問" aria-label="Permalink to &quot;4-14. よくある質問&quot;">​</a></h2><p><strong>Q1. レポートの数字が合わない</strong></p><p>A1. 期間指定のミスが多い。「営業日区切り時刻」（デフォルト 05:00）を確認。深夜 1 時の売上が「翌日」扱いになっていないか。</p><p><strong>Q2. 粗利が表示されない</strong></p><p>A2. 粗利表示には <strong>レシピ設定</strong>（品目と原材料の紐付け）が必要。在庫・レシピ管理タブで設定してください。</p><p><strong>Q3. スタッフ評価の「担当注文」とは？</strong></p><p>A3. ハンディで注文入力した個人スタッフ、または POSレジで会計担当に指定されたスタッフの注文です。</p><p><strong>Q4. ABC 分析が見えない</strong></p><p>A4. ABC 分析は <strong>オーナー専用</strong>です。オーナーアカウントでオーナー管理画面にログインしてください。</p><p><strong>Q5. CSV ダウンロードしたら改行がおかしい</strong></p><p>A5. Excel で直接開くと表示が崩れることがあります。「データ」→「テキストまたはCSVから」で取り込み、文字コードを UTF-8 に指定してください。</p><hr><h2 id="_4-15-詳細は" tabindex="-1">4-15. 詳細は <a class="header-anchor" href="#_4-15-詳細は" aria-label="Permalink to &quot;4-15. 詳細は&quot;">​</a></h2><p>→ <a href="./../tenant/13-reports.html">13 章 レポート</a></p><hr><h2 id="_4-16-次のページへ" tabindex="-1">4-16. 次のページへ <a class="header-anchor" href="#_4-16-次のページへ" aria-label="Permalink to &quot;4-16. 次のページへ&quot;">​</a></h2><p>→ <a href="./part5-reservations.html">Part 5: 予約管理</a></p>',149)])])}const _=a(e,[["render",o]]);export{u as __pageData,_ as default};
